﻿/**
 * Button Component (Static Version)
 *
 * A production-grade button without motion animations.
 * Uses CSS transitions for subtle feedback while avoiding motion library dependencies.
 *
 * This is the static variant - use the animated variant for full spring animations.
 *
 * @packageDocumentation
 */

"use client";

// =============================================================================
// IMPORTS
// =============================================================================

import * as React from "react";
import {
  forwardRef,
  useCallback,
  type ComponentPropsWithoutRef,
  type ElementRef,
} from "react";

import { Slot } from "@/lib/primitives";
import { cva, type VariantProps } from "class-variance-authority";
import type { Icon } from "@phosphor-icons/react";

import { cn } from "@/lib/utils";
import { useRipple } from "@/hooks/use-ripple";
import { StaticLoadingSpinner, StaticCheck } from "@/lib/icons-static";

// =============================================================================
// VARIANTS (CVA)
// =============================================================================

const buttonVariants = cva(
  [
    "inline-flex items-center justify-center gap-2 whitespace-nowrap shrink-0",
    "text-sm font-medium",
    "rounded-lg",
    "transition-[color,background-color,border-color,box-shadow,transform] duration-150",
    "disabled:pointer-events-none disabled:opacity-50",
    "[&_svg]:pointer-events-none [&_svg:not([class*='size-'])]:size-4 [&_svg]:shrink-0",
    "outline-none",
    "focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-background",
    "aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive",
    "select-none",
    // CSS-based interaction feedback
    "active:scale-[0.98] active:transition-transform",
  ].join(" "),
  {
    variants: {
      variant: {
        default: [
          "bg-primary text-primary-foreground",
          "shadow-sm shadow-primary/20",
          "hover:bg-primary/90 hover:shadow-md hover:shadow-primary/25",
          "active:shadow-sm",
        ].join(" "),

        destructive: [
          "bg-destructive text-white",
          "shadow-sm shadow-destructive/20",
          "hover:bg-destructive/90 hover:shadow-md hover:shadow-destructive/25",
          "focus-visible:ring-destructive/20 dark:focus-visible:ring-destructive/40",
          "dark:bg-destructive/80",
        ].join(" "),

        outline: [
          "border border-input bg-background",
          "shadow-xs",
          "hover:bg-accent hover:text-accent-foreground hover:border-accent-foreground/20",
          "dark:bg-input/30 dark:border-input dark:hover:bg-input/50",
        ].join(" "),

        secondary: [
          "bg-secondary text-secondary-foreground",
          "shadow-xs",
          "hover:bg-secondary/80 hover:shadow-sm",
        ].join(" "),

        ghost: [
          "hover:bg-accent hover:text-accent-foreground",
          "dark:hover:bg-accent/50",
        ].join(" "),

        link: ["text-primary underline-offset-4", "hover:underline"].join(" "),
      },

      size: {
        default: "h-10 px-5 py-2.5 has-[>svg]:px-4",
        sm: "h-9 rounded-md gap-1.5 px-4 text-xs has-[>svg]:px-3",
        lg: "h-11 rounded-lg px-7 text-base has-[>svg]:px-5",
        xl: "h-12 rounded-xl px-8 text-base has-[>svg]:px-6",
        icon: "size-10",
        "icon-sm": "size-9",
        "icon-lg": "size-11",
      },
    },

    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
);

// =============================================================================
// COMPONENT PROPS
// =============================================================================

export interface ButtonProps
  extends
    Omit<ComponentPropsWithoutRef<"button">, "ref">,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean;
  loading?: boolean;
  success?: boolean;
  iconStart?: Icon;
  iconEnd?: Icon;
}

// =============================================================================
// BUTTON COMPONENT
// =============================================================================

const Button = forwardRef<ElementRef<"button">, ButtonProps>(
  (
    {
      className,
      variant,
      size,
      asChild = false,
      loading = false,
      success = false,
      iconStart: IconStart,
      iconEnd: IconEnd,
      disabled,
      children,
      onClick,
      ...props
    },
    ref,
  ) => {
    const isDisabled = disabled || loading;
    const { ripples, createRipple } = useRipple();
    const showRipple = variant !== "ghost" && variant !== "link";

    const handleClick = useCallback(
      (event: React.MouseEvent<HTMLButtonElement>) => {
        if (!loading && !success && showRipple) {
          createRipple(event);
        }
        onClick?.(event);
      },
      [loading, success, showRipple, createRipple, onClick],
    );

    const iconSize = size === "sm" || size === "icon-sm" ? 14 : 16;

    const iconStartContent =
      IconStart && !loading && !success ? (
        <IconStart className="shrink-0" size={iconSize} aria-hidden="true" />
      ) : null;

    const loadingSpinner = loading ? <StaticLoadingSpinner size={iconSize} /> : null;

    const successCheck =
      success && !loading ? <StaticCheck size={iconSize} /> : null;

    const iconEndContent =
      IconEnd && !loading && !success ? (
        <IconEnd className="shrink-0" size={iconSize} aria-hidden="true" />
      ) : null;

    const buttonContent = (
      <>
        <span className="relative z-10 flex items-center justify-center gap-2">
          {loadingSpinner}
          {successCheck}
          {iconStartContent}
          {children}
          {iconEndContent}
        </span>

        {showRipple && (
          <span
            className="pointer-events-none absolute inset-0 overflow-hidden"
            style={{
              opacity: loading || success ? 0 : 1,
              transition: "opacity 200ms ease-out",
            }}
            aria-hidden="true"
          >
            {ripples.map((ripple) => (
              <span
                className="animate-rippling absolute rounded-full opacity-30"
                key={ripple.key}
                style={{
                  width: `${ripple.size}px`,
                  height: `${ripple.size}px`,
                  top: `${ripple.y}px`,
                  left: `${ripple.x}px`,
                  backgroundColor: "currentColor",
                  transform: "scale(0)",
                }}
              />
            ))}
          </span>
        )}
      </>
    );

    const commonProps = {
      "data-slot": "button",
      "data-loading": loading || undefined,
      "data-success": success || undefined,
      className: cn(
        buttonVariants({ variant, size, className }),
        showRipple && "relative overflow-hidden",
      ),
      disabled: isDisabled,
      "aria-busy": loading || undefined,
      "aria-disabled": isDisabled || undefined,
      onClick: handleClick,
      ...props,
    };

    if (asChild) {
      return (
        <Slot ref={ref} {...commonProps}>
          {children}
        </Slot>
      );
    }

    return (
      <button ref={ref} {...commonProps}>
        {buttonContent}
      </button>
    );
  },
);

Button.displayName = "Button";

// =============================================================================
// ICON BUTTON COMPONENT
// =============================================================================

export interface IconButtonProps extends Omit<
  ButtonProps,
  "iconStart" | "iconEnd" | "children" | "asChild"
> {
  icon: Icon;
  "aria-label": string;
}

const IconButton = forwardRef<ElementRef<"button">, IconButtonProps>(
  ({ icon, size = "icon", ...props }, ref) => {
    return <Button ref={ref} size={size} iconStart={icon} {...props} />;
  },
);

IconButton.displayName = "IconButton";

// =============================================================================
// EXPORTS
// =============================================================================

export { Button, IconButton, buttonVariants };
export type { ButtonProps as ButtonRootProps };

"use client";

import { useState, useCallback, useEffect } from "react";
import type * as React from "react";

/**
 * Ripple effect data structure
 */
export interface Ripple {
  x: number;
  y: number;
  size: number;
  key: number;
}

/**
 * Hook to manage ripple effects on button click
 *
 * Creates expanding circular ripples from the click point,
 * automatically cleaning up after animation completes.
 */
export function useRipple() {
  const [ripples, setRipples] = useState<Ripple[]>([]);

  const createRipple = useCallback(
    (event: React.MouseEvent<HTMLButtonElement>) => {
      const button = event.currentTarget;
      const rect = button.getBoundingClientRect();
      const size = Math.max(rect.width, rect.height);
      const x = event.clientX - rect.left - size / 2;
      const y = event.clientY - rect.top - size / 2;

      const newRipple: Ripple = { x, y, size, key: Date.now() };
      setRipples((prev) => [...prev, newRipple]);
    },
    [],
  );

  // Auto-cleanup ripples after animation
  useEffect(() => {
    if (ripples.length > 0) {
      const lastRipple = ripples[ripples.length - 1];
      const timeout = setTimeout(() => {
        setRipples((prev) => prev.filter((r) => r.key !== lastRipple.key));
      }, 600);
      return () => clearTimeout(timeout);
    }
  }, [ripples]);

  return { ripples, createRipple };
}

/**
 * Static Icons Library
 *
 * CSS-only icon components for static components.
 * No motion/react dependency - uses pure CSS animations.
 *
 * These are drop-in replacements for the animated icon components
 * when using the static variant.
 *
 * @packageDocumentation
 */

"use client";

import * as React from "react";
import type { Icon } from "@phosphor-icons/react";
import { cn } from "@/lib/utils";

// =============================================================================
// STATIC LOADING SPINNER
// CSS-only spinning loader
// =============================================================================

export interface StaticLoadingSpinnerProps {
  /** Size of the spinner in pixels */
  size?: number;
  /** Stroke width */
  strokeWidth?: number;
  /** Additional className */
  className?: string;
  /** Whether to show the spinner */
  show?: boolean;
}

/**
 * StaticLoadingSpinner - CSS-only loading indicator
 *
 * Uses CSS animation instead of motion/react for rotation.
 */
export function StaticLoadingSpinner({
  size = 16,
  strokeWidth = 2,
  className,
  show = true,
}: StaticLoadingSpinnerProps) {
  if (!show) return null;

  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill="none"
      className={cn("animate-spin", className)}
      aria-hidden="true"
    >
      <circle
        cx="12"
        cy="12"
        r="10"
        stroke="currentColor"
        strokeWidth={strokeWidth}
        strokeOpacity={0.25}
        fill="none"
      />
      <path
        d="M12 2C6.477 2 2 6.477 2 12"
        stroke="currentColor"
        strokeWidth={strokeWidth}
        strokeLinecap="round"
        fill="none"
      />
    </svg>
  );
}

// =============================================================================
// STATIC CHECKMARK ICON
// CSS-only check mark for success states
// =============================================================================

export interface StaticCheckProps {
  /** Size of the checkmark in pixels */
  size?: number;
  /** Stroke width */
  strokeWidth?: number;
  /** Additional className */
  className?: string;
  /** Whether to show the checkmark */
  show?: boolean;
}

/**
 * StaticCheck - Simple checkmark without draw animation
 *
 * Shows immediately with a fade-in effect.
 */
export function StaticCheck({
  size = 24,
  strokeWidth = 2,
  className,
  show = true,
}: StaticCheckProps) {
  if (!show) return null;

  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill="none"
      className={cn("animate-in fade-in-0 zoom-in-95 duration-200", className)}
      aria-hidden="true"
    >
      <path
        d="M5 13l4 4L19 7"
        stroke="currentColor"
        strokeWidth={strokeWidth}
        strokeLinecap="round"
        strokeLinejoin="round"
        fill="none"
      />
    </svg>
  );
}

// =============================================================================
// STATIC CLOSE BUTTON
// CSS-only close button
// =============================================================================

export interface StaticCloseButtonProps {
  /** Click handler */
  onClick?: () => void;
  /** Size of the button */
  size?: "sm" | "md" | "lg";
  /** Additional className */
  className?: string;
  /** ARIA label */
  "aria-label"?: string;
}

const sizeMap = {
  sm: { button: 24, icon: 14 },
  md: { button: 32, icon: 18 },
  lg: { button: 40, icon: 22 },
};

/**
 * StaticCloseButton - Close button with CSS transitions
 */
export function StaticCloseButton({
  onClick,
  size = "md",
  className,
  "aria-label": ariaLabel = "Close",
}: StaticCloseButtonProps) {
  const dimensions = sizeMap[size];

  return (
    <button
      type="button"
      onClick={onClick}
      className={cn(
        "inline-flex items-center justify-center rounded-full",
        "bg-muted/50 text-muted-foreground",
        "transition-all duration-150 ease-out",
        "hover:bg-muted hover:text-foreground hover:scale-105",
        "active:scale-95",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
        className,
      )}
      style={{
        width: dimensions.button,
        height: dimensions.button,
      }}
      aria-label={ariaLabel}
    >
      <svg
        width={dimensions.icon}
        height={dimensions.icon}
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth={2}
        strokeLinecap="round"
        strokeLinejoin="round"
        aria-hidden="true"
      >
        <path d="M18 6L6 18" />
        <path d="M6 6l12 12" />
      </svg>
    </button>
  );
}

// =============================================================================
// STATIC ICON WRAPPER
// Wraps Phosphor icons with optional CSS transitions
// =============================================================================

export interface StaticIconProps extends React.SVGProps<SVGSVGElement> {
  /** The Phosphor icon component to render */
  icon: Icon;
  /** Size of the icon */
  size?: number | string;
  /** Stroke width */
  strokeWidth?: number;
  /** Additional className */
  className?: string;
}

/**
 * StaticIcon - Renders a Phosphor icon without motion dependencies
 *
 * Use this as a drop-in replacement for AnimatedIcon in static components.
 */
export function StaticIcon({
  icon: IconComponent,
  className,
  size,
  strokeWidth = 2,
  ...props
}: StaticIconProps) {
  return (
    <span className={cn("inline-flex shrink-0", className)}>
      <IconComponent
        size={size}
        strokeWidth={strokeWidth}
        {...(props as React.SVGProps<SVGSVGElement>)}
      />
    </span>
  );
}

// =============================================================================
// STATIC ICON MORPH
// Switches between icons with CSS transition
// =============================================================================

export interface StaticIconMorphProps {
  /** First icon (shown when isActive is false) */
  iconA: Icon;
  /** Second icon (shown when isActive is true) */
  iconB: Icon;
  /** Current state */
  isActive: boolean;
  /** Icon size */
  size?: number | string;
  /** Stroke width */
  strokeWidth?: number;
  /** Additional className */
  className?: string;
}

/**
 * StaticIconMorph - Switches between two icons with CSS fade
 *
 * Use this as a drop-in replacement for IconMorph in static components.
 */
export function StaticIconMorph({
  iconA: IconA,
  iconB: IconB,
  isActive,
  size = 24,
  strokeWidth = 2,
  className,
}: StaticIconMorphProps) {
  const CurrentIcon = isActive ? IconB : IconA;

  return (
    <span
      className={cn(
        "relative inline-flex items-center justify-center",
        "transition-transform duration-150 ease-out",
        className,
      )}
      style={{ width: size, height: size }}
    >
      <CurrentIcon
        size={size}
        strokeWidth={strokeWidth}
        className="animate-in fade-in-0 zoom-in-95 duration-150"
      />
    </span>
  );
}

// =============================================================================
// STATIC CHEVRON
// Rotatable chevron with CSS transitions
// =============================================================================

export interface StaticChevronProps {
  /** Direction/rotation state */
  direction: "up" | "down" | "left" | "right";
  /** Size of the chevron */
  size?: number;
  /** Additional className */
  className?: string;
}

const directionRotation = {
  up: "-rotate-180",
  down: "rotate-0",
  left: "rotate-90",
  right: "-rotate-90",
};

/**
 * StaticChevron - CSS-animated rotatable chevron
 */
export function StaticChevron({
  direction = "down",
  size = 16,
  className,
}: StaticChevronProps) {
  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth={2}
      strokeLinecap="round"
      strokeLinejoin="round"
      className={cn(
        "transition-transform duration-200 ease-out",
        directionRotation[direction],
        className,
      )}
      aria-hidden="true"
    >
      <polyline points="6 9 12 15 18 9" />
    </svg>
  );
}

// =============================================================================
// LOADING DOTS
// CSS-only animated loading dots
// =============================================================================

export interface StaticLoadingDotsProps {
  /** Size of each dot */
  dotSize?: number;
  /** Gap between dots */
  gap?: number;
  /** Additional className */
  className?: string;
}

/**
 * StaticLoadingDots - Three bouncing dots animation
 */
export function StaticLoadingDots({
  dotSize = 4,
  gap = 4,
  className,
}: StaticLoadingDotsProps) {
  return (
    <span
      className={cn("inline-flex items-center", className)}
      style={{ gap }}
      aria-hidden="true"
    >
      {[0, 1, 2].map((i) => (
        <span
          key={i}
          className="rounded-full bg-current static-loading-dot"
          style={{
            width: dotSize,
            height: dotSize,
            animationDelay: `${i * 0.16}s`,
          }}
        />
      ))}
    </span>
  );
}
